public class Main {
    public static void main(String[] args) {
        int number = 20;
        int steps = 0;

        while (number > 1) {
            if (number % 2 == 0) {
                number = number / 2;
            } else {
                number = number * 3 + 1;
            }
            steps++;
        }

        System.out.println("Steps to reach 1: " + steps);
    }
}

